func (s *server) CompileAndDescribe(ctx context.Context, req *pb.CompileProtoRequest) (*pb.DescribeResponse, error) {
	log.Printf("Received CompileAndDescribe request for file: %s", req.ProtoFilename)

	descriptorBytes, err := s.compileProto(ctx, req.ProtoDefinition, req.ProtoFilename)
	if err != nil {
		return &pb.DescribeResponse{
			Success: false,
			Message: err.Error(),
		}, nil
	}

	// Parse the descriptor set
	fdSet := &descriptorpb.FileDescriptorSet{}
	if err := proto.Unmarshal(descriptorBytes, fdSet); err != nil {
		return nil, status.Errorf(codes.Internal, "failed to parse descriptor set: %v", err)
	}

	response := &pb.DescribeResponse{
		Success: true,
		Message: "Compilation and description successful",
	}

	for _, fd := range fdSet.GetFile() {
		// Extract messages
		for _, msgDesc := range fd.GetMessageType() {
			msgInfo := &pb.MessageInfo{
				Name: msgDesc.GetName(),
			}
			for _, fieldDesc := range msgDesc.GetField() {
				fieldInfo := &pb.FieldInfo{
					Name:   fieldDesc.GetName(),
					Type:   fieldDesc.GetType().String(),
					Number: fieldDesc.GetNumber(),
				}
				msgInfo.Fields = append(msgInfo.Fields, fieldInfo)
			}
			response.Messages = append(response.Messages, msgInfo)
		}

		// Extract services
		for _, svcDesc := range fd.GetService() {
			svcInfo := &pb.ServiceInfo{
				Name: svcDesc.GetName(),
			}
			for _, methodDesc := range svcDesc.GetMethod() {
				methodInfo := &pb.ServiceMethodInfo{
					Name:       methodDesc.GetName(),
					InputType:  methodDesc.GetInputType(),
					OutputType: methodDesc.GetOutputType(),
				}
				svcInfo.Methods = append(svcInfo.Methods, methodInfo)
			}
			response.Services = append(response.Services, svcInfo)
		}
	}

	return response, nil
}

